// HasUser applies the HasEdge predicate on the "user" edge.
func HasUser() predicate.VoucherOrder {
	return predicate.VoucherOrder(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, UserTable, UserColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUserWith applies the HasEdge predicate on the "user" edge with a given conditions (other predicates).
func HasUserWith(preds ...predicate.User) predicate.VoucherOrder {
	return predicate.VoucherOrder(func(s *sql.Selector) {
		step := newUserStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.VoucherOrder) predicate.VoucherOrder {
	return predicate.VoucherOrder(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.VoucherOrder) predicate.VoucherOrder {
	return predicate.VoucherOrder(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.VoucherOrder) predicate.VoucherOrder {
	return predicate.VoucherOrder(sql.NotPredicates(p))
}
